VALUES
  ('real-estate-moex-02292', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '14歲之甲未得父母之允許，對同學為債務免除之意思表示，其效力如何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02293', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲欲購買乙所有房屋1棟，經數次與乙磋商之後，雙方同意該屋以500萬元成交，並詳細約定付款及交 屋、移轉所有權方式，為求慎重並由丙丁 2 人擔任見證人，且言明為免日後爭議，應將約定內容寫成契 約書。嗣後因乙反悔，結果連契約書都無法完成。則下列敘述何者正確？', '["因為無法完成契約書，因此甲乙之契約不成立", "甲如果已經給付部分價金，應以不當得利請求返還", "甲如能證明與乙已有訂立契約之合意，仍得請求乙履行", "甲為了使乙履行契約，應先請求乙完成契約書"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02294', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲為房屋仲介公司之員工，經甲之斡旋乙同意將其所有房屋出售於丙，乙丙雙方皆委任甲處理登記及付 款事宜並授與代理權，事成之後乙丙應支付甲相當之報酬。以下敘述何者錯誤？', '["此時雖屬所謂雙方代理，但因已經本人許諾，故可有效", "甲有要事需出國，乃將辦理登記事宜委託同事丁代為處理，因丁之疏失致丙受損害，由於甲並無過失 可以無庸負責", "由於委任之事項中包含不動產登記事宜，就此部分包含代理權之授與應做成書面契約", "甲處理相關事務時，應以善良管理人之注意程度，謹慎為之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02295', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲男與乙女為男女朋友關係，甲同意將其名下之豪宅贈與乙，以下之敘述何者錯誤？', '["甲在未移轉該屋之所有權給乙之前，隨時可以向乙表示反悔，撤銷贈與", "贈與為單獨行為", "甲在未移轉房屋所有權給乙之前，因為電線走火將該屋燒毀時，除非甲有故意重大過失，否則無庸負 給付不能之責任", "甲移轉該屋之所有權給乙，乙搬入該屋之後，即使發現該屋漏水嚴重，原則上亦無法請求甲修繕"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02296', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲受僱於乙客運公司擔任公車司機，某日在依照路線載客途中，因過失撞傷路人丙。下列敘述何者錯誤？', '["丙可以只向甲請求賠償", "丙可以只向乙請求賠償", "乙賠償之後，原則上可以向甲主張求償", "甲乙對丙負不真正連帶債務之關係"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02297', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲至乙家具行購買 1 組展示中之沙發，約定於隔日由乙送貨至甲指定之處所。乙之員工丙送貨途中，因 精神不濟發生翻車事故，沙發全毀，以下敘述何者錯誤？', '["雖然沙發係因丙之過失而毀損，乙仍須負債務不履行之責任", "因為尚有另外1組圖案類似之沙發，甲可請求乙交付該組沙發替代", "乙可以向丙主張沙發毀損之損害賠償", "甲必須解除契約之後，才能免除給付價金之債務"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02298', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲使用乙銀行發行之信用卡消費後，共計有15萬元卡債無法返還，乙銀行在未知會甲之情形下，將該筆 債權出售給丙。下列敘述何者錯誤？', '["因為甲未受到任何通知，故乙丙之讓與行為無效", "甲乙之間如果有設定擔保，該擔保亦隨同由丙取得", "甲乙之間如果有特約約定該筆債權不得讓與，丙公司如屬善意時，其讓與仍然有效", "甲欲清償債務時，經第3人告知，才知乙已將債權讓與丙，乃主動向丙清償債務，此屬有效之行為"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02299', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '以下有關租賃關係之敘述何者正確？', '["租賃物如有修繕之必要，基於使用者付費之原則，應由承租人負擔修繕之費用", "承租人有使用收益租賃物之權利，所以可以自行將房間分租，當二房東", "甲將其房屋出租與乙，言明租期3年，有訂立契約書但未公證。至第2年時甲將房屋所有權讓與丙， 乙得向丙主張該租賃契約仍存在", "租賃之房屋因電線走火發生火災，房屋因而受損時，因承租人未盡善良管理人之責，應負損害賠償責任"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02300', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '銀行對於肉眼顯能辨識之票據印文真偽，而未為辨識，其責任係屬何種性質之責任？', '["屬重大過失之責任", "屬抽象輕過失之責任", "屬具體輕過失之責任", "無過失責任"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02301', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '基於下列何種原因而取得利益，應依關於不當得利之規定，返還其所受利益？', '["因確定判決取得利益", "因添附取得利益", "因消滅時效取得利益", "因取得時效取得利益"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
